client/editor.js :: initImageEditor
function initImageEditor(elements, options = {}) {
  editor.canvas = elements.canvas;
  editor.ctx = elements.canvas.getContext("2d");
  editor.overlay = elements.overlay;
  editor.wrap = elements.wrap;
  editor.input = elements.input;
  onFilesChange = options.onFilesChange || null;

  elements.input.addEventListener("change", () => {
    syncEditorToSelection();
    if (onFilesChange) onFilesChange();
  });

  editor.canvas.addEventListener("mousedown", startDrag);
  editor.canvas.addEventListener("mousemove", moveDrag);
  window.addEventListener("mouseup", endDrag);

  [
    elements.cropX,
    elements.cropY,
    elements.cropW,
    elements.cropH,
    elements.resizeW,
    elements.resizeH,
  ].forEach((input) => {
    input.addEventListener("change", syncCropFromInputs);
  });

  elements.resetCropBtn.addEventListener("click", resetCropToFull);
}

client/editor.js :: getSelectedFileCount
function getSelectedFileCount() {
  return editor.input?.files?.length || 0;
}

client/editor.js :: isSingleFileMode
function isSingleFileMode() {
  return getSelectedFileCount() === 1;
}

client/editor.js :: syncEditorToSelection
function syncEditorToSelection() {
  const count = getSelectedFileCount();
  if (count === 1) {
    loadSelectedFile(editor.input);
    return;
  }
  editor.naturalWidth = 0;
  editor.naturalHeight = 0;
  if (editor.wrap) editor.wrap.hidden = true;
}

client/editor.js :: loadSelectedFile
async function loadSelectedFile(input) {
  const file = input.files?.[0];
  if (!file) {
    editor.wrap.hidden = true;
    return;
  }

  const url = URL.createObjectURL(file);
  const image = new Image();
  image.onload = () => {
    editor.naturalWidth = image.naturalWidth;
    editor.naturalHeight = image.naturalHeight;
    const maxSide = 420;
    const scale = Math.min(1, maxSide / Math.max(image.naturalWidth, image.naturalHeight));
    editor.displayWidth = Math.max(1, Math.round(image.naturalWidth * scale));
    editor.displayHeight = Math.max(1, Math.round(image.naturalHeight * scale));

    editor.canvas.width = editor.displayWidth;
    editor.canvas.height = editor.displayHeight;
    editor.ctx.drawImage(image, 0, 0, editor.displayWidth, editor.displayHeight);
    URL.revokeObjectURL(url);

    resetCropToFull();
    editor.wrap.hidden = false;
    drawCropOverlay();
  };
  image.onerror = () => {
    URL.revokeObjectURL(url);
    editor.wrap.hidden = true;
  };
  image.src = url;
}

client/editor.js :: resetCropToFull
function resetCropToFull() {
  editor.crop = {
    x: 0,
    y: 0,
    w: editor.naturalWidth,
    h: editor.naturalHeight,
  };
  syncInputsFromCrop();
  drawCropOverlay();
}

client/editor.js :: syncInputsFromCrop
function syncInputsFromCrop() {
  const cropX = document.getElementById("cropX");
  const cropY = document.getElementById("cropY");
  const cropW = document.getElementById("cropW");
  const cropH = document.getElementById("cropH");
  if (!cropX) return;
  cropX.value = editor.crop.x;
  cropY.value = editor.crop.y;
  cropW.value = editor.crop.w;
  cropH.value = editor.crop.h;
  const resizeW = document.getElementById("resizeW");
  const resizeH = document.getElementById("resizeH");
  if (resizeW && !resizeW.value) resizeW.placeholder = String(editor.crop.w);
  if (resizeH && !resizeH.value) resizeH.placeholder = String(editor.crop.h);
}

client/editor.js :: syncCropFromInputs
function syncCropFromInputs() {
  if (!editor.naturalWidth) return;
  const cropX = Number(document.getElementById("cropX").value);
  const cropY = Number(document.getElementById("cropY").value);
  const cropW = Number(document.getElementById("cropW").value);
  const cropH = Number(document.getElementById("cropH").value);
  const x = clamp(cropX, 0, editor.naturalWidth - 1);
  const y = clamp(cropY, 0, editor.naturalHeight - 1);
  editor.crop = {
    x,
    y,
    w: clamp(cropW, 1, editor.naturalWidth - x),
    h: clamp(cropH, 1, editor.naturalHeight - y),
  };
  drawCropOverlay();
}

client/editor.js :: displayToNaturalX
function displayToNaturalX(x) {
  return Math.round((x / editor.displayWidth) * editor.naturalWidth);
}

client/editor.js :: displayToNaturalY
function displayToNaturalY(y) {
  return Math.round((y / editor.displayHeight) * editor.naturalHeight);
}

client/editor.js :: naturalToDisplayX
function naturalToDisplayX(x) {
  return (x / editor.naturalWidth) * editor.displayWidth;
}

client/editor.js :: naturalToDisplayY
function naturalToDisplayY(y) {
  return (y / editor.naturalHeight) * editor.displayHeight;
}

client/editor.js :: startDrag
function startDrag(event) {
  if (!editor.naturalWidth) return;
  const rect = editor.canvas.getBoundingClientRect();
  editor.dragging = true;
  editor.dragStart = {
    x: event.clientX - rect.left,
    y: event.clientY - rect.top,
  };
  editor.crop = {
    x: displayToNaturalX(editor.dragStart.x),
    y: displayToNaturalY(editor.dragStart.y),
    w: 1,
    h: 1,
  };
}

client/editor.js :: moveDrag
function moveDrag(event) {
  if (!editor.dragging || !editor.dragStart) return;
  const rect = editor.canvas.getBoundingClientRect();
  const currentX = clamp(event.clientX - rect.left, 0, editor.displayWidth);
  const currentY = clamp(event.clientY - rect.top, 0, editor.displayHeight);

  const x0 = Math.min(editor.dragStart.x, currentX);
  const y0 = Math.min(editor.dragStart.y, currentY);
  const x1 = Math.max(editor.dragStart.x, currentX);
  const y1 = Math.max(editor.dragStart.y, currentY);

  const left = displayToNaturalX(x0);
  const top = displayToNaturalY(y0);
  const right = displayToNaturalX(x1);
  const bottom = displayToNaturalY(y1);

  editor.crop = {
    x: left,
    y: top,
    w: Math.max(1, right - left),
    h: Math.max(1, bottom - top),
  };
  syncInputsFromCrop();
  drawCropOverlay();
}

client/editor.js :: endDrag
function endDrag() {
  editor.dragging = false;
  editor.dragStart = null;
}

client/editor.js :: drawCropOverlay
function drawCropOverlay() {
  if (!editor.overlay || !editor.naturalWidth) return;
  const left = naturalToDisplayX(editor.crop.x);
  const top = naturalToDisplayY(editor.crop.y);
  const width = naturalToDisplayX(editor.crop.x + editor.crop.w) - left;
  const height = naturalToDisplayY(editor.crop.y + editor.crop.h) - top;

  editor.overlay.style.left = `${left}px`;
  editor.overlay.style.top = `${top}px`;
  editor.overlay.style.width = `${width}px`;
  editor.overlay.style.height = `${height}px`;
}

client/editor.js :: getEditFormFields
function getEditFormFields() {
  const fields = {
    filter: document.getElementById("filter")?.value || "none",
  };

  const resizeW = document.getElementById("resizeW")?.value;
  const resizeH = document.getElementById("resizeH")?.value;
  if (resizeW) fields.resize_w = resizeW;
  if (resizeH) fields.resize_h = resizeH;

  if (isSingleFileMode() && editor.naturalWidth && editor.crop.w > 0 && editor.crop.h > 0) {
    fields.crop_x = String(editor.crop.x);
    fields.crop_y = String(editor.crop.y);
    fields.crop_w = String(editor.crop.w);
    fields.crop_h = String(editor.crop.h);
  }

  return fields;
}

client/editor.js :: appendEditFields
function appendEditFields(formData) {
  const fields = getEditFormFields();
  for (const [key, value] of Object.entries(fields)) {
    if (value !== undefined && value !== "") {
      formData.append(key, value);
    }
  }
}

client/editor.js :: clamp
function clamp(value, min, max) {
  return Math.min(max, Math.max(min, value));
}
